INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('optometrist-moex-03644', 'optometrist', 'optometrist-moex-106-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '關於散光隱形眼鏡鏡片（toric lens）的設計，下列敘述何者錯誤？', '["眼皮作用下，稜鏡垂重（prism ballast）設計的軟式散光鏡片，周邊稜鏡基底朝上旋轉（base-up），穩 定鏡片定位", "眼皮作用下，上下削薄（double slab off）設計的軟式散光鏡片，上下邊固定於眼皮下，穩定鏡片定位", "硬式鏡片的後散光設計，利用改變鏡片後表面弧度，使其更服貼於角膜表面、減低角膜散光", "硬式鏡片的前散光設計，利用稜鏡垂重原理，將鏡片散光設計在前表面、減低晶體散光"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:56+00:00", "source_pdf_sha1": "43136df1aeb4", "answer_pdf_sha1": "f9cf08f73c11", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03645', 'optometrist', 'optometrist-moex-106-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '下列特殊隱形眼鏡驗配敘述，何者錯誤？', '["圓錐角膜（keratoconus）患者，宜將鏡片基弧弧度縮小，避免壓迫角膜錐（cone）使角膜反覆破皮", "不規則散光者，可用揹負式（piggyback）配鏡，在硬式鏡片前表面覆蓋軟式鏡片，提高配戴舒適度", "淚水缺乏乾眼症患者，可用鏡片矢高大的鞏膜鏡（scleral lens），蓄積眼表淚水，減緩症狀", "先天性紅色弱患者，可使用特殊彩色隱形眼鏡，加強其色覺辨識度"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:56+00:00", "source_pdf_sha1": "43136df1aeb4", "answer_pdf_sha1": "f9cf08f73c11", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03646', 'optometrist', 'optometrist-moex-106-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '利用表面印染法（surface printing）與夾層印染法（laminate printing）製作的彩色隱形眼鏡，下列敘述何 者錯誤？', '["表面印染法將色料印在隱形眼鏡前表面，容易造成鏡片表面平滑度下降，且色料易脫落", "表面印染法將色料印在隱形眼鏡後表面，不易造成鏡片表面平滑度下降，且色料不易脫落", "夾層法將色料包夾在鏡片中，較不會有色料脫落問題", "夾層法將色料包夾在鏡片中，鏡面平滑，較不會產生沉澱物與細菌附著"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:56+00:00", "source_pdf_sha1": "43136df1aeb4", "answer_pdf_sha1": "f9cf08f73c11", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03647', 'optometrist', 'optometrist-moex-106-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '關於逆幾何設計（reverse geometry）的隱形眼鏡，下列敘述何者錯誤？', '["逆幾何設計指鏡片中央光學區基弧比鄰近的第二弧來的平", "鏡片直徑有設計限制，最大直徑不能超過角膜直徑", "可應用於角膜塑型術（orthokeratology），暫時性改變角膜弧度", "可應用於驗配雷射近視手術（LASIK）後的扁圓（oblate）角膜"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:56+00:00", "source_pdf_sha1": "43136df1aeb4", "answer_pdf_sha1": "f9cf08f73c11", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03648', 'optometrist', 'optometrist-moex-106-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '關於老花軟式隱形眼鏡的設計，下列敘述何者錯誤？', '["非球面（aspheric design）設計的軟式老花鏡片，必須設計中心區為看遠、周邊看近", "非球面設計的軟式老花鏡片可能的缺點是，瞳孔大小變動或鏡片移位時，視力表現不穩定", "同心雙焦點（concentric, bifocal）設計的老花鏡片，若其光學轉換區（alternating zones）能設計在瞳孔 變動範圍內，則視力表現較不受瞳孔大小影響", "交替視覺設計（alternating/ translating vision）的老花鏡片，通過注視不同鏡片區域獲得遠、中、近視力， 其光學品質應較同步視覺設計（simultaneous vision）的鏡片為佳"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:56+00:00", "source_pdf_sha1": "43136df1aeb4", "answer_pdf_sha1": "f9cf08f73c11", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03649', 'optometrist', 'optometrist-moex-106-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '關於一般自動角膜弧度測量儀（autokeratometry），下列何者錯誤？', '["驗測時，頭位與眼位偏斜可能導致測量誤差", "驗測時，淚膜不均勻可能導致測量誤差", "驗測時，可測得角膜頂尖（corneal apex）的弧度", "驗測時，角膜頂尖若有偏位（eccentric）可能導致測量誤差"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:56+00:00", "source_pdf_sha1": "43136df1aeb4", "answer_pdf_sha1": "f9cf08f73c11", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03650', 'optometrist', 'optometrist-moex-106-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '關於細隙燈生體顯微鏡（slit-lamp biomicroscopy）觀察與推論，下列敘述何者最不合理？', '["患者拆除鏡片後見到角膜三、九點鐘方向破皮，可能是拆除方法不正確或鏡片太緊", "患者眼輪部觀察到顯著新生血管合併周邊角膜輕微水腫，可能是表示角膜缺氧", "患者的下眼瞼緣淚鏡（tear meniscus）高度在長期配戴隱形眼鏡後，從0.5毫米變為0.3毫米，可能是 淚水分泌功能變差", "患者的淚膜破裂時間（tear break-up time）在長期配戴隱形眼鏡後，從15秒變為5秒，可能是淚膜穩定 度提高"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:56+00:00", "source_pdf_sha1": "43136df1aeb4", "answer_pdf_sha1": "f9cf08f73c11", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03651', 'optometrist', 'optometrist-moex-106-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '下列關於隱形眼鏡之併發症敘述，何者錯誤？', '["長時間使用彈性係數高的矽水膠鏡片，可能引起上方弓形結膜破損（superior epithelial arcuate lesion, SEAL）", "長期使用硬式鏡片，可能引起上眼瞼下垂", "長期使用揹負式合併軟硬式鏡片使用，相較於單純配戴硬式鏡片，較不會刺激眼輪部新生血管產生", "使用大直徑鏡片如鞏膜鏡，若鏡片滑動大，會增加鏡後淚液層碎骸（debris）產生"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:56+00:00", "source_pdf_sha1": "43136df1aeb4", "answer_pdf_sha1": "f9cf08f73c11", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03652', 'optometrist', 'optometrist-moex-106-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '隱形眼鏡使用者，經檢查發現過敏性結膜炎，上下眼瞼結膜處（palpebral conjunctiva）可發現大量乳突 （papillae）合併眼睛紅癢與分泌物增多，下列處置何者最不適當？', '["暫時停戴鏡片，給予抗過敏藥物治療", "將患者的長戴式鏡片轉為拋棄式鏡片，並增加鏡片替換頻率", "將患者清潔鏡片用雙氧水系統改為多功能護理液浸泡後直接配戴，較能舒緩結膜刺激", "給予無防腐劑人工淚水減緩症狀"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:56+00:00", "source_pdf_sha1": "43136df1aeb4", "answer_pdf_sha1": "f9cf08f73c11", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03653', 'optometrist', 'optometrist-moex-106-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '隱形眼鏡配戴者，拆下鏡片後出現急性紅眼，下列處置何者最不適當？', '["詢問相關症狀如畏光、疼痛、溢淚", "檢查取下之鏡片有無破損、是否仍有殘餘鏡片在眼部", "觀察角膜表面是否平整、有無大範圍破皮或混濁", "儘快給予加壓包紮（pressure patching）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:56+00:00", "source_pdf_sha1": "43136df1aeb4", "answer_pdf_sha1": "f9cf08f73c11", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
